mapper.select:
SELECT id, course_name, course_category, course_level, course_type,
       start_date, duration, instructor, price, original_price,
       course_description, course_image, tags, enroll_count, status,
       created_at, updated_at
FROM training_courses
WHERE status = 1

    AND course_category = #{category}


    AND course_level = #{level}


    AND course_type = #{type}

ORDER BY start_date ASC
